// @Target：適用対象の制限
// ElementType.TYPE → クラス、インターフェース、列挙型
// ElementType.METHOD → メソッド
// ElementType.FIELD → フィールド
// ElementType.PARAMETER → パラメータ
// ElementType.CONSTRUCTOR → コンストラクタ
// ElementType.LOCAL_VARIABLE → ローカル変数

// @Retention：保持ポリシー
// RetentionPolicy.SOURCE → ソースコードのみ（コンパイル後に破棄）
// RetentionPolicy.CLASS → クラスファイルに保持（デフォルト）
// RetentionPolicy.RUNTIME → 実行時にリフレクションで取得可能

@Target(ElementType.METHOD)
@Retention(RetentionPolicy.RUNTIME)
@interface MyAnnotation {
    String value();
}

