import java.lang.annotation.*;

// マーカーアノテーション（要素なし）
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface Test {}

// 単一値アノテーション
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.TYPE)
@interface Author {
    String value();  // 要素名がvalueなら使用時に省略可能
}

// 複数要素のアノテーション
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface Todo {
    String description();
    String assignee() default "未定";
    int priority() default 3;
}

// 使用例
@Author("Taro")  // value()なので要素名省略可
// MyAppクラスの定義
class MyApp {
    @Test
    // testMethodメソッドの定義
    void testMethod() {}

    @Todo(description = "実装する", priority = 1)
    // futureMethodメソッドの定義
    void futureMethod() {}
}

import java.lang.annotation.*;

