contents.body:
@Repeatableを使うと、同じ**アノテーション**を同じ要素に複数回適用できます。
@Repeatableには「格納用アノテーション（コンテナアノテーション）」を指定する必要があります。
コンテナアノテーションにはvalue()要素が必要で、その型は繰り返し対象のアノテーションの[[配列]]です。
コンテナアノテーションの@Retentionと@Targetは、繰り返し対象のアノテーションと合わせる必要があります。

contents.code:
import java.lang.annotation.*;

// 1. 繰り返し可能なアノテーション
@Repeatable(Roles.class)  // コンテナを指定
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.TYPE)
@interface Role {
    String value();
}

// 2. コンテナアノテーション
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.TYPE)
@interface Roles {
    Role[] value();  // 繰り返し対象の配列
}

// 3. 使用例：同じアノテーションを複数回適用
@Role("admin")
@Role("manager")
@Role("user")
// MultiRoleUserクラスの定義
class MultiRoleUser {
}

// コンテナアノテーションで直接書くことも可能
@Roles({@Role("admin"), @Role("manager")})
// AnotherUserクラスの定義
class AnotherUser {
}

import java.lang.annotation.*;
import java.lang.reflect.Method;

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface Info {
    String author();
    String date();
}

// Serviceクラスの定義
class Service {
    @Info(author = "Taro", date = "2024-04-01")
    // processメソッドの定義
    public void process() {
        System.out.println("処理実行");
    }

    // otherメソッドの定義
    public void other() {}
}

// リフレクションでアノテーション取得
// Mainクラスの定義
public class Main {
    public static void main(String[] args) throws Exception {
        Method method = Service.class.getMethod("process");

        // アノテーションの有無を確認
        // 条件分岐
        if (method.isAnnotationPresent(Info.class)) {
            Info info = method.getAnnotation(Info.class);
            System.out.println("作者: " + info.author());
            System.out.println("日付: " + info.date());
        }
        // 出力:
        // 作者: Taro
        // 日付: 2024-04-01

        // すべてのアノテーションを取得
        Annotation[] anns = method.getAnnotations();
        // 拡張for文（コレクションの全要素を順番に処理）
        for (Annotation a : anns) {
            System.out.println(a);
        }
    }
}

