import java.lang.annotation.*;

// @Repeatableアノテーションの取得
// @Role("admin") @Role("manager") が付いた MultiRoleUser

Class<?> clazz = MultiRoleUser.class;

// 方法1：getAnnotationsByType()で直接取得
Role[] roles = clazz.getAnnotationsByType(Role.class);
for (Role r : roles) {
    System.out.println(r.value());
}
// admin
// manager
// user

// 方法2：コンテナアノテーション経由
Roles container = clazz.getAnnotation(Roles.class);
if (container != null) {
    for (Role r : container.value()) {
        System.out.println(r.value());
    }
}

// 1回だけの場合
// @Role("admin") class SingleRoleUser {}
// getAnnotation(Roles.class) → null
// getAnnotation(Role.class) → @Role("admin")
// getAnnotationsByType(Role.class) → {@Role("admin")}

